  values (131,'Sea Legs','{"Modern Classic","Martini"}','Rocks','Lime wheel or Angostura bitters line','#c8d8b0','Shake peated whisky, mezcal, orgeat, and lime juice with ice. Double-strain into a rocks glass over a single large ice cube (optional). Dash celery bitters over the top, then draw a line of Angostura if you have the skills — or float a lime wheel.','[{"name":"Islay Scotch","oz":1,"displayAmt":null},{"name":"Mezcal","oz":1,"displayAmt":null},{"name":"Orgeat","oz":0.75,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null},{"name":"Celery Bitters","oz":null,"displayAmt":"2-3 dashes"},{"name":"Angostura Bitters","oz":null,"displayAmt":"1 dash"}]'::jsonb,null,'Mezcal/celery riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (132,'Enzoni','{"Modern Classic","Bitter"}','Rocks','Green grape, orange slice','#c5e1a5','Add green grapes to a shaker and muddle gently. Add gin, Campari, lemon juice, and simple syrup. Shake with ice. Double-strain over fresh ice into a rocks glass. Garnish with a grape and orange slice. Created by Vincenzo Errico at Milk & Honey, NYC — a cross between a Negroni and a Gin Sour.','[{"name":"Gin","oz":1,"displayAmt":null},{"name":"Campari","oz":1,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null},{"name":"Simple Syrup","oz":0.5,"displayAmt":null},{"name":"Green Grapes","oz":null,"displayAmt":"5 grapes, muddled"}]'::jsonb,null,'Grape riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (133,'Division Bell','{"Sour","Modern Classic","Bitter"}','Coupe','Grapefruit twist (expressed and discarded)','#ff8a65','Combine all ingredients in a shaker with ice. Shake until well chilled. Double-strain into a chilled coupe. Express a grapefruit peel over the surface to release its oils, then discard. Created by Phil Ward at Mayahuel, NYC in 2009 — a mezcal riff on the Last Word, named after the Pink Floyd album he listened to while building the bar.','[{"name":"Mezcal","oz":1,"displayAmt":null},{"name":"Aperol","oz":0.75,"displayAmt":null},{"name":"Maraschino Liqueur","oz":0.75,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null}]'::jsonb,null,'Mezcal riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (134,'Daiquiri','{"Sour","Classic"}','Coupe','Lime wheel','#f0fbe8','Combine rum, lime juice, and simple syrup in a shaker with ice. Shake hard for 10–12 seconds. Double-strain into a chilled coupe. The Daiquiri is one of the six basic drinks in "The Fine Art of Mixing Drinks" — simplicity is its virtue.','[{"name":"Rum","oz":2,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null},{"name":"Simple Syrup","oz":0.75,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (135,'Bloody Mary','{"Classic","Highball"}','Highball','Celery stalk, lemon wedge','#c0392b','Build in a highball glass over ice. Add vodka, tomato juice, lemon juice, Worcestershire, hot sauce, horseradish, and seasonings. Roll between two glasses to mix gently. Adjust seasoning to taste. Garnish generously.','[{"name":"Vodka","oz":1.5,"displayAmt":null},{"name":"Tomato Juice","oz":3,"displayAmt":null},{"name":"Lemon Juice","oz":0.5,"displayAmt":null},{"name":"Worcestershire Sauce","oz":null,"displayAmt":"2 dashes"},{"name":"Hot Sauce","oz":null,"displayAmt":"2 dashes"},{"name":"Horseradish","oz":null,"displayAmt":"1 tsp"},{"name":"Celery Salt","oz":null,"displayAmt":"pinch"},{"name":"Black Pepper","oz":null,"displayAmt":"pinch"}]'::jsonb,null,null)
