insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (136,'Old Pal','{"Classic","Spirit Forward"}','Coupe','Lemon twist','#d05830','Combine all ingredients in a mixing glass with ice. Stir for 30 seconds until well chilled. Strain into a chilled coupe. Express a lemon peel over the surface and discard or twist on the rim. A drier, boozier cousin of the Boulevardier.','[{"name":"Rye Whiskey","oz":1,"displayAmt":null},{"name":"Campari","oz":1,"displayAmt":null},{"name":"Dry Vermouth","oz":1,"displayAmt":null}]'::jsonb,null,'Rye & dry vermouth')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (138,'Trinidad Sour','{"Sour","Modern Classic"}','Coupe','None','#c0392b','Combine all ingredients in a shaker with ice. Shake vigorously — the orgeat needs to integrate fully with the bitters. Double-strain into a chilled coupe. Created by Giuseppe González at Painkiller, NYC. An astonishing drink built on an entire ounce of Angostura bitters.','[{"name":"Angostura Bitters","oz":1,"displayAmt":null},{"name":"Rye Whiskey","oz":0.5,"displayAmt":null},{"name":"Orgeat","oz":1,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (139,'Bitter Giuseppe','{"Classic","Bitter"}','Rocks','Lemon twist','#704214','Combine all ingredients in a mixing glass with ice. Stir for 30–40 seconds until well chilled and diluted. Strain over a large ice cube in a rocks glass. Express a lemon peel over the surface. Created by Stephen Cole. The equal-parts Cynar build makes this one of the most approachable amaro drinks.','[{"name":"Cynar","oz":2,"displayAmt":null},{"name":"Sweet Vermouth","oz":1,"displayAmt":null},{"name":"Lemon Juice","oz":null,"displayAmt":"¼ oz"},{"name":"Orange Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (140,'Ferrari','{"Classic","Bitter"}','Rocks','Orange twist','#a03028','Build over ice in a rocks glass or combine in a mixing glass and stir. Pour Fernet-Branca and Campari in equal parts over ice. Stir briefly. Express an orange peel over the surface. A bartender''s handshake — two of the most polarising amari united Fernet-Branca is the standard fernet used here.','[{"name":"Fernet","oz":1.5,"displayAmt":null},{"name":"Campari","oz":1.5,"displayAmt":null}]'::jsonb,null,'Fernet riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (141,'Trident','{"Classic","Bitter"}','Coupe','Lemon twist','#a8a050','Combine all ingredients in a mixing glass with ice. Stir for 30 seconds. Strain into a chilled coupe. Express a lemon peel over the surface. Created by Robert Hess. An aquavit-based sibling of the Negroni using three low-ABV, underappreciated spirits.','[{"name":"Aquavit","oz":1,"displayAmt":null},{"name":"Cynar","oz":1,"displayAmt":null},{"name":"Dry Sherry","oz":1,"displayAmt":null},{"name":"Peach Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,'Aquavit riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (142,'Black Manhattan','{"Classic","Modern Classic","Spirit Forward"}','Coupe','Maraschino cherry','#3a1a10','Combine rye or bourbon with Averna in a mixing glass with ice. Add bitters. Stir for 30 seconds. Strain into a chilled coupe or Nick & Nora. Garnish with a cherry. Swap sweet vermouth for Averna amaro — darker, more herbal, slightly bitter Amaro Averna is the classic choice — rich, bittersweet, and herbal.','[{"name":"Rye Whiskey","oz":2,"displayAmt":null},{"name":"Amaro Averna","oz":1,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"1 dash"},{"name":"Orange Bitters","oz":null,"displayAmt":"1 dash"}]'::jsonb,null,'Averna riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (143,'Benton''s Old Fashioned','{"Modern Classic","Spirit Forward"}','Rocks','Orange twist','#d4820a','Fat-wash the bourbon: combine 1.5 oz warm bacon fat with bourbon, let sit 4 hours, freeze, and remove solidified fat. Combine fat-washed bourbon with maple syrup and bitters in a mixing glass with ice. Stir for 30 seconds. Strain over large ice. Created by Don Lee at PDT, NYC — the drink that launched the fat-washing technique.','[{"name":"Bourbon","oz":2,"displayAmt":null},{"name":"Grade B Maple Syrup","oz":null,"displayAmt":"¼ tsp"},{"name":"Angostura Bitters","oz":null,"displayAmt":"2 dashes"},{"name":"Mole Bitters","oz":null,"displayAmt":"1 dash"}]'::jsonb,null,'Fat-washed riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (144,'Jet Pilot','{"Tiki"}','Tiki','Mint sprig, lime wheel','#b85c38','Combine all ingredients in a blender with 1 cup of cracked ice. Blend for 5 seconds. Pour unstrained into a tiki mug. Garnish with a mint sprig and lime wheel. A vintage Don the Beachcomber original — high-octane rum blend with Donn''s Spices.','[{"name":"Rum","oz":0.75,"displayAmt":null},{"name":"Dark Rum","oz":0.75,"displayAmt":null},{"name":"Overproof Rum","oz":0.5,"displayAmt":null},{"name":"Lime Juice","oz":0.5,"displayAmt":null},{"name":"Grapefruit Juice","oz":0.5,"displayAmt":null},{"name":"Cinnamon Syrup","oz":0.5,"displayAmt":null},{"name":"Falernum","oz":0.5,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"1 dash"},{"name":"Absinthe","oz":null,"displayAmt":"1 drop"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (145,'Pearl Diver','{"Tiki","Frozen"}','Tiki','Gardenia flower, mint','#f0a830','Combine all ingredients with 1 cup of crushed ice in a blender. Blend briefly — about 5 seconds. Pour into a tiki mug or pearl diver glass. Gardenia Mix: blend 1 oz softened butter, 1 oz honey, 1 oz cinnamon syrup. A Don the Beachcomber original known for its silky, gardenia mix–enriched texture.','[{"name":"Rum","oz":1,"displayAmt":null},{"name":"Dark Rum","oz":1,"displayAmt":null},{"name":"Gardenia Mix","oz":0.75,"displayAmt":null},{"name":"Orange Juice","oz":0.5,"displayAmt":null},{"name":"Lime Juice","oz":0.5,"displayAmt":null},{"name":"Passion Fruit Syrup","oz":0.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (146,'Saturn','{"Tiki"}','Tiki','Cherry, mint sprig','#f5e840','Combine all ingredients in a shaker with ice. Shake well. Strain into a chilled tiki glass or large coupe. Garnish with a cherry and mint. Created by J. ''Popo'' Galsini for the 1967 IBA World Cocktail Championship. Gin-based tiki — a rare and wonderful thing.','[{"name":"Gin","oz":1.5,"displayAmt":null},{"name":"Lemon Juice","oz":0.5,"displayAmt":null},{"name":"Falernum","oz":0.5,"displayAmt":null},{"name":"Orgeat","oz":0.25,"displayAmt":null},{"name":"Passion Fruit Syrup","oz":0.25,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (147,'Fog Cutter','{"Tiki"}','Tiki','Mint bouquet, orange slice','#f5c842','Combine all ingredients except sherry in a shaker with ice. Shake well. Strain over crushed ice into a tiki mug. Float the sweet sherry on top. Created by Trader Vic Bergeron in 1945. One of the few tiki drinks to feature three base spirits.','[{"name":"Rum","oz":2,"displayAmt":null},{"name":"Brandy","oz":1,"displayAmt":null},{"name":"Gin","oz":0.5,"displayAmt":null},{"name":"Orange Juice","oz":1,"displayAmt":null},{"name":"Lemon Juice","oz":1,"displayAmt":null},{"name":"Orgeat","oz":0.5,"displayAmt":null},{"name":"Sweet Sherry","oz":0.5,"displayAmt":null}]'::jsonb,null,'Multi-spirit riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (148,'Japanese Highball','{"Highball"}','Highball','Lemon peel twist','#f8f8e8','Chill a highball glass thoroughly. Add one large ice cube and stir 13 times to chill the glass. Pour in the whisky and stir 3 times clockwise. Top slowly with chilled carbonated water and stir once from bottom to top. Express a lemon peel and drop in. Technique is everything — carbonation must be preserved.','[{"name":"Whiskey","oz":1.5,"displayAmt":null},{"name":"Soda Water","oz":4.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (149,'Wray & Ting','{"Highball"}','Highball','Lime wedge','#f8f0a0','Fill a highball glass with ice. Add overproof rum. Top with Ting grapefruit soda and stir gently. Squeeze in a lime wedge and drop in. One of the simplest and most refreshing highballs — the Jamaican rum funk paired with tart grapefruit is elemental.','[{"name":"Overproof Rum","oz":2,"displayAmt":null},{"name":"Grapefruit Soda","oz":4,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (150,'Fernet & Coke','{"Highball","Bitter"}','Highball','Lime wedge','#1a1a1a','Fill a highball glass with ice. Pour in Fernet-Branca. Top with cola and stir gently once or twice. Add a lime wedge. The national drink of Argentina — known locally as ''Fernando''. The bitterness of Fernet and the sweetness of cola is more than the sum of its parts.','[{"name":"Fernet","oz":1.5,"displayAmt":null},{"name":"Cola","oz":4.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (151,'Pimm''s Cup','{"Highball","Classic"}','Highball','Cucumber ribbon, strawberry, mint, lemon','#c87830','Fill a highball glass with ice. Pour in Pimm''s No. 1. Top with lemonade (or ginger ale) and stir gently. Load with garnishes — the more the better. A cucumber ribbon is essential. The quintessential British summer drink, inseparable from Wimbledon and Henley.','[{"name":"Pimm''s No. 1","oz":2,"displayAmt":null},{"name":"Lemonade","oz":4,"displayAmt":null},{"name":"Cucumber","oz":null,"displayAmt":"slices"},{"name":"Strawberries","oz":null,"displayAmt":"2, sliced"},{"name":"Mint","oz":null,"displayAmt":"sprig"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (152,'Vermouth & Soda','{"Low-ABV","Highball"}','Wine','Lemon twist or olive','#e8f0d8','Fill a wine glass or highball with ice. Pour in dry or white vermouth. Top with chilled sparkling water and stir gently once. Add garnish of choice. An aperitivo staple across Italy and Spain — refreshing, low-alcohol, and endlessly flexible.','[{"name":"Dry Vermouth","oz":2,"displayAmt":null},{"name":"Soda Water","oz":2,"displayAmt":null}]'::jsonb,null,'Vermouth soda riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (153,'Grasshopper','{"Classic","Creamy"}','Coupe','Chocolate shavings','#50c060','Combine all ingredients in a shaker with ice. Shake vigorously until very cold and frothy. Double-strain into a chilled coupe. Garnish with chocolate shavings or a small mint sprig. Created at Tujague''s in New Orleans around 1919. Minty, creamy, and entirely retro.','[{"name":"White Crème de Menthe","oz":1,"displayAmt":null},{"name":"Crème de Cacao","oz":1,"displayAmt":null},{"name":"Cream","oz":1,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (154,'Chartreuse Swizzle','{"Modern Classic","Tiki"}','Highball','Pineapple wedge, mint','#78b830','Add all ingredients to a highball glass filled with crushed ice. Swizzle vigorously using a barspoon between palms until the glass frosts. Top with more crushed ice and garnish. Created by Marcovaldo Dionysos at Absinthe Brasserie, San Francisco. Green Chartreuse in its purest and most refreshing form.','[{"name":"Green Chartreuse","oz":1.5,"displayAmt":null},{"name":"Pineapple Juice","oz":1,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null},{"name":"Falernum","oz":0.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (155,'Bloody Caesar','{"Classic","Highball"}','Highball','Celery stalk, lime wedge, pickle','#b03020','Rim a highball glass with celery salt. Fill with ice. Add vodka, Clamato juice, Worcestershire, hot sauce, and seasonings. Stir gently. Garnish generously — the Caesar is known for its elaborate garnishes. Invented by Walter Chell in Calgary, 1969. Canada''s national cocktail.','[{"name":"Vodka","oz":1.5,"displayAmt":null},{"name":"Clamato Juice","oz":4,"displayAmt":null},{"name":"Worcestershire Sauce","oz":null,"displayAmt":"3 dashes"},{"name":"Hot Sauce","oz":null,"displayAmt":"3 dashes"},{"name":"Celery Salt","oz":null,"displayAmt":"rim"},{"name":"Black Pepper","oz":null,"displayAmt":"pinch"},{"name":"Lime Juice","oz":0.5,"displayAmt":null}]'::jsonb,null,'Clamato riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (156,'Army and Navy','{"Sour","Classic"}','Coupe','Lemon or grapefruit twist','#f0e8a0','Combine gin, lemon juice, and orgeat in a shaker with ice. Add a dash of Angostura bitters if desired — it adds complexity and deepens the color. Shake well and double-strain into a chilled coupe. Express a lemon or grapefruit peel over the surface. A Prohibition-era gin sour made silky and nutty by the orgeat.','[{"name":"Gin","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":1,"displayAmt":null},{"name":"Orgeat","oz":0.75,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"1 dash (optional)"}]'::jsonb,null,'Orgeat riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (157,'Mocha Martini','{"Martini","Modern Classic"}','Martini','Three coffee beans','#2a1008','Combine all ingredients in a shaker with ice. Shake hard for 12 seconds to get a good foam. Double-strain into a chilled martini glass. Garnish with three espresso beans. A richer, chocolate-forward riff on the Espresso Martini — crème de cacao replaces the coffee liqueur. Chocolate bitters are an excellent addition.','[{"name":"Vodka","oz":1.5,"displayAmt":null},{"name":"Espresso","oz":1,"displayAmt":null},{"name":"Crème de Cacao","oz":0.75,"displayAmt":null},{"name":"Chocolate Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,'Chocolate riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (158,'Final Ward','{"Sour","Modern Classic"}','Coupe','Lemon twist','#d0e890','Combine all ingredients in equal parts in a shaker with ice. Shake well and double-strain into a chilled coupe. Garnish with a lemon twist. The Final Ward is a Last Word riff by Phil Ward — rye replaces gin and lemon replaces lime, shifting the whole drink warmer and drier.','[{"name":"Rye Whiskey","oz":0.75,"displayAmt":null},{"name":"Green Chartreuse","oz":0.75,"displayAmt":null},{"name":"Maraschino Liqueur","oz":0.75,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null}]'::jsonb,null,'Rye & lemon riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (159,'Midori Sour','{"Sour"}','Rocks','Lemon wheel','#78c840','Add all ingredients to a rocks glass filled with ice and stir, or shake with ice and strain over fresh ice. Adjust Midori to taste — more Midori gives a sweeter, more melon-forward drink. Top with a small dash of club soda or lemon-lime soda if desired. Garnish with a lemon wheel.','[{"name":"Midori","oz":1.5,"displayAmt":null},{"name":"Vodka","oz":1,"displayAmt":null},{"name":"Lime Juice","oz":0.5,"displayAmt":null},{"name":"Lemon Juice","oz":0.5,"displayAmt":null},{"name":"Soda Water","oz":null,"displayAmt":"splash"}]'::jsonb,null,'Midori riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (160,'Smoke on the Boulevard','{"Modern Classic","Spirit Forward"}','Coupe','Brandied cherry','#d07030','Combine all ingredients in a mixing glass with ice. Stir for 30 seconds until well chilled. Strain into a chilled coupe. Garnish with a brandied cherry. A stirred, spirit-forward riff that splits the difference between a Boulevardier and a Black Manhattan — the Aperol brightens, the Averna deepens Averna works well as the amaro component.','[{"name":"Rye Whiskey","oz":1.5,"displayAmt":null},{"name":"Aperol","oz":0.5,"displayAmt":null},{"name":"Amaro Averna","oz":0.5,"displayAmt":null},{"name":"Sweet Vermouth","oz":0.5,"displayAmt":null}]'::jsonb,null,'Stirred riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (161,'Left Hand','{"Modern Classic","Classic","Spirit Forward"}','Coupe','Brandied cherry','#b03028','Combine all ingredients in a mixing glass with ice. Stir for 30 seconds until well chilled and properly diluted. Strain into a chilled coupe. Garnish with a brandied cherry. The Left Hand is a Manhattan/Negroni mashup by Sam Ross — the chocolate bitters tie the rye and Campari together beautifully.','[{"name":"Rye Whiskey","oz":2,"displayAmt":null},{"name":"Sweet Vermouth","oz":0.75,"displayAmt":null},{"name":"Campari","oz":0.75,"displayAmt":null},{"name":"Chocolate Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,'Negroni mashup')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (162,'Cranberry Sour','{"Sour","Frozen"}','Coupe','Lime wheel, mint','#e01858','Blend defrosted cranberries with Cointreau, amaretto, orange juice, lime juice, and maple syrup until smooth. Strain through a fine sieve, pressing pulp firmly to extract all liquid. Chill thoroughly. To serve, fill small glasses or coupes with crushed ice and pour over the deep pink cocktail. Can be made in large batches ahead of time.','[{"name":"Frozen Cranberries","oz":null,"displayAmt":"300g, defrosted"},{"name":"Orange Liqueur","oz":null,"displayAmt":"100ml"},{"name":"Amaretto","oz":null,"displayAmt":"1 tbsp"},{"name":"Orange Juice","oz":null,"displayAmt":"100ml"},{"name":"Lime Juice","oz":null,"displayAmt":"2 tbsp"},{"name":"Maple Syrup","oz":null,"displayAmt":"2–3 tbsp"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (163,'Spanish G&T','{"Highball","Classic"}','Wine','Rosemary, cucumber, citrus, juniper berries','#e8f5e0','Fill a large wine glass or copa de balon with ice. Add gin and top slowly with tonic — Mediterranean tonic adds extra citrus character. Do not stir; let the tonic settle naturally. Load generously with aromatics: rosemary, mint, basil, juniper berries, peppercorns, citrus peels, and a long thin cucumber slice. Each garnish should be chosen to complement the gin''s botanicals.','[{"name":"Gin","oz":1.5,"displayAmt":null},{"name":"Mediterranean Tonic","oz":4,"displayAmt":null},{"name":"Rosemary","oz":null,"displayAmt":"sprig"},{"name":"Cucumber","oz":null,"displayAmt":"long slice"},{"name":"Citrus Peel","oz":null,"displayAmt":"lemon & orange"}]'::jsonb,null,'Spanish style')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (164,'Cardinale','{"Classic","Spirit Forward"}','Rocks','Lemon twist','#e84030','Combine gin, Campari, and dry vermouth in a mixing glass with ice. Stir for 30 seconds. Strain over a large ice cube into a rocks glass. Express a lemon peel over the surface and drop in or rest on the rim. The Cardinale is a Negroni with dry vermouth in place of sweet — drier, more bitter, and more aromatic.','[{"name":"Gin","oz":1.5,"displayAmt":null},{"name":"Campari","oz":0.75,"displayAmt":null},{"name":"Dry Vermouth","oz":0.75,"displayAmt":null}]'::jsonb,null,'Dry vermouth riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (165,'Amaro Sour','{"Sour","Modern Classic","Bitter"}','Rocks','Lemon twist','#804010','Combine all ingredients in a shaker without ice. Dry shake for 20–30 seconds to emulsify the egg white fully. Add ice and shake hard for another 15 seconds. Strain into a rocks glass over a large ice cube. The egg white gives a silky, frothy texture; the bourbon adds backbone to balance the bitter amaro Averna is an excellent amaro choice here.','[{"name":"Amaro Averna","oz":1.5,"displayAmt":null},{"name":"Bourbon","oz":0.75,"displayAmt":null},{"name":"Lemon Juice","oz":1,"displayAmt":null},{"name":"Simple Syrup","oz":0.25,"displayAmt":null},{"name":"Egg White","oz":null,"displayAmt":"1 white"}]'::jsonb,null,'Amaro riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (166,'The Cigar','{"Modern Classic","Spirit Forward"}','Coupe','Scorched cinnamon stick','#c87820','Combine sweet vermouth, Laphroaig, and Aperol in a mixing glass with ice. Stir for 30–40 seconds until well chilled. Strain into a chilled coupe. Express grapefruit oil over the surface by squeezing a wide strip of grapefruit peel — do not drop it in. Garnish with a scorched cinnamon stick if desired. Cocchi Vermouth di Torino is the ideal sweet vermouth here — its bitter orange notes complement the peated scotch beautifully. in a mixing glass with ice. Stir for 30–40 seconds until well chilled. Strain into a chilled coupe. Express grapefruit oil over the surface by squeezing a wide strip of grapefruit peel — do not drop it in. Garnish with a scorched cinnamon stick if desired. The peated scotch, bitter orange, and sweet vermouth create something that genuinely evokes a good cigar.','[{"name":"Sweet Vermouth","oz":1.5,"displayAmt":null},{"name":"Islay Scotch","oz":1,"displayAmt":null},{"name":"Aperol","oz":0.5,"displayAmt":null},{"name":"Grapefruit Peel","oz":null,"displayAmt":"for oil, expressed"}]'::jsonb,null,'Sweet vermouth riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (167,'Smoke and Fire','{"Sour","Modern Classic"}','Rocks','Lime wedge, dried chile','#c8a840','Rim a chilled rocks glass with lime juice and sea salt. Combine all ingredients in a shaker with ice and shake until well chilled. Strain into the salt-rimmed glass over a large ice cube or small cubes. Garnish with a lime wedge and a dried chile. The equal-parts tequila and mezcal split gives smoke and brightness; Ancho Reyes Verde adds a fresh green heat.','[{"name":"Blanco Tequila","oz":0.75,"displayAmt":null},{"name":"Mezcal","oz":0.75,"displayAmt":null},{"name":"Ancho Reyes Verde","oz":0.75,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null},{"name":"Agave Nectar","oz":0.33,"displayAmt":null},{"name":"Sea Salt","oz":null,"displayAmt":"rim"}]'::jsonb,null,'Mezcal riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (168,'Debbie Don''t','{"Sour","Modern Classic","Spirit Forward"}','Coupe','Lemon twist','#d4a020','Combine all ingredients in a shaker with ice. Shake well until chilled. Double-strain into a chilled coupe. Garnish with a lemon twist. The reposado tequila and Averna make for an earthy, bittersweet base, balanced by the bright lemon and rounded sweetness of maple syrup Averna is recommended for the amaro.','[{"name":"Tequila","oz":1,"displayAmt":null},{"name":"Amaro Averna","oz":1,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null},{"name":"Maple Syrup","oz":0.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (169,'Eggnog (Alton Brown)','{"Hot","Classic","Creamy"}','Rocks','Freshly grated nutmeg','#f5e0a0','1. Separate the eggs and reserve whites for another use. 2. Beat yolks with sugar and nutmeg until lightened in color and falling off the whisk in a solid ribbon. 3. Combine dairy, booze, and salt in a second vessel, then slowly beat into the egg mixture. 4. Transfer to glass jars and refrigerate for a minimum of 2 weeks — a month is better, two months better still. The aging mellows and melds everything. 5. Serve in mugs or cups topped with freshly grated nutmeg. Can also be drunk immediately if you can''t wait. Alton Brown''s definitive aged eggnog — the booze cures the eggs so no cooking required.','[{"name":"Egg Yolks","oz":null,"displayAmt":"600g eggs"},{"name":"Sugar","oz":null,"displayAmt":"454g"},{"name":"Freshly Grated Nutmeg","oz":null,"displayAmt":"1 tsp"},{"name":"Half-and-Half","oz":null,"displayAmt":"480ml"},{"name":"Milk","oz":null,"displayAmt":"473ml"},{"name":"Cream","oz":null,"displayAmt":"480ml"},{"name":"Rum","oz":null,"displayAmt":"237ml"},{"name":"Cognac","oz":null,"displayAmt":"237ml"},{"name":"Bourbon","oz":null,"displayAmt":"237ml"},{"name":"Kosher Salt","oz":null,"displayAmt":"0.3 tsp"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (170,'Martini','{"Martini","Classic"}','Martini','Expressed lemon peel','#eef8f0','Chill your glass first — it makes a huge difference. Add gin, dry vermouth, and a fat dash of orange bitters to a mixing glass with ice. Stir well until cold and properly diluted, about 30 seconds. Strain into the chilled coupe or martini glass of your choice. Express the lemon oil over the surface by squeezing a trimmed lemon peel over the drink, then garnish with the peel. St. George Terroir gin is highly recommended here — its savory, forest-floor botanicals are exceptional in a martini. Dolin dry vermouth keeps things clean and lightly floral. This is a relatively wet (2:1) martini. Many prefer much drier — try 4:1 or even 6:1 gin to vermouth depending on your taste.','[{"name":"Gin","oz":1.5,"displayAmt":null},{"name":"Dry Vermouth","oz":0.75,"displayAmt":null},{"name":"Orange Bitters","oz":null,"displayAmt":"1 fat dash"},{"name":"Lemon Peel","oz":null,"displayAmt":"for expression & garnish"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (171,'French Connection','{"Classic","Martini"}','Rocks','None','#c8a050','Build in a rocks glass over ice. Add cognac and amaretto. Stir briefly to combine. No garnish needed — the drink speaks for itself. A simple equal-parts digestif-style drink from the 1970s.','[{"name":"Cognac","oz":1.5,"displayAmt":null},{"name":"Amaretto","oz":1.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (172,'Rusty Nail','{"Classic","Martini"}','Rocks','Lemon twist','#c07818','Build in a rocks glass over a large ice cube. Add Scotch, then Drambuie. Stir gently to combine without over-diluting. Garnish with a lemon twist. The Drambuie brings honey and heather sweetness to the Scotch; use a ratio anywhere from 2:1 to 4:1 depending on how sweet you like it.','[{"name":"Scotch","oz":2,"displayAmt":null},{"name":"Drambuie","oz":0.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (173,'Godfather','{"Classic","Martini"}','Rocks','None','#a06018','Build in a rocks glass over ice. Add Scotch and amaretto, stir briefly. A Godfather swaps Drambuie for amaretto — slightly nuttier and less sweet than a Rusty Nail. Use 2:1 Scotch to amaretto as a starting point and adjust to taste.','[{"name":"Scotch","oz":2,"displayAmt":null},{"name":"Amaretto","oz":0.75,"displayAmt":null}]'::jsonb,null,'Amaretto riff on Rusty Nail')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (174,'Godmother','{"Classic","Martini"}','Rocks','None','#d8c8a0','Build in a rocks glass over ice. Add vodka and amaretto, stir briefly. The Godmother is the vodka counterpart to the Godfather — clean and neutral where the Godfather is smoky. Great for those who find Scotch too assertive.','[{"name":"Vodka","oz":2,"displayAmt":null},{"name":"Amaretto","oz":0.75,"displayAmt":null}]'::jsonb,null,'Vodka riff on Rusty Nail')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (175,'John Collins','{"Classic","Highball"}','Highball','Lemon slice, cherry','#e0c858','Add bourbon to a highball glass over ice. Add lemon juice and simple syrup. Top with soda water and stir gently. Garnish with a lemon slice and cherry. Essentially a Tom Collins made with whiskey instead of gin — bourbon or rye both work well.','[{"name":"Bourbon","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":1,"displayAmt":null},{"name":"Simple Syrup","oz":0.5,"displayAmt":null},{"name":"Soda Water","oz":3,"displayAmt":null}]'::jsonb,null,'Whiskey version')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (176,'Jack Rose','{"Classic","Sour"}','Coupe','Lemon twist','#f08070','Combine applejack or calvados, lemon juice, and grenadine in a shaker with ice. Shake vigorously for 15 seconds. Strain into a chilled coupe. Garnish with a lemon twist. The grenadine gives a beautiful blush color and pomegranate sweetness that plays against the apple brandy. Use quality grenadine if possible.','[{"name":"Brandy","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null},{"name":"Grenadine","oz":0.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (177,'Widow''s Kiss','{"Classic","Sour"}','Coupe','Brandied cherry','#a8c850','Combine calvados or apple brandy, Yellow Chartreuse, Benedictine, and Angostura bitters in a mixing glass with ice. Stir for 30 seconds. Strain into a chilled coupe. Garnish with a brandied cherry. An 1895 classic from George Kappeler — Benedictine and Chartreuse together create extraordinary botanical depth.','[{"name":"Brandy","oz":1.5,"displayAmt":null},{"name":"Yellow Chartreuse","oz":0.75,"displayAmt":null},{"name":"Bénédictine","oz":0.75,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (178,'Brooklyn','{"Classic","Modern Classic","Spirit Forward"}','Coupe','Maraschino cherry','#b84030','Combine rye whiskey, dry vermouth, maraschino liqueur, and a dash of bitters in a mixing glass with ice. Stir for 30 seconds. Strain into a chilled coupe. Garnish with a maraschino cherry. The Brooklyn swaps sweet vermouth for dry and adds maraschino — drier and more complex than a Manhattan. Traditionally calls for Amer Picon; Torani Amer or a small amount of Campari work as substitutes.','[{"name":"Rye Whiskey","oz":2,"displayAmt":null},{"name":"Dry Vermouth","oz":0.75,"displayAmt":null},{"name":"Maraschino Liqueur","oz":null,"displayAmt":"1 tsp"},{"name":"Angostura Bitters","oz":null,"displayAmt":"1 dash"}]'::jsonb,null,'Maraschino and dry vermouth riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (179,'Tipperary','{"Classic","Sour"}','Coupe','Orange twist','#98b840','Combine Irish whiskey, sweet vermouth, and Green Chartreuse in a mixing glass with ice. Stir for 30 seconds. Strain into a chilled coupe. Garnish with an orange twist. A pre-Prohibition classic — the Green Chartreuse adds a wildly herbal quality that transforms whiskey and vermouth into something far greater than the sum of its parts.','[{"name":"Irish Whiskey","oz":1.5,"displayAmt":null},{"name":"Sweet Vermouth","oz":0.75,"displayAmt":null},{"name":"Green Chartreuse","oz":0.25,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (180,'Gin Fizz','{"Classic","Highball"}','Highball','Lemon wheel','#e8f8d0','Combine gin, lemon juice, and simple syrup in a shaker with ice. Shake well for 15 seconds. Strain into a chilled highball glass without ice. Top with soda water. Garnish with a lemon wheel. Key difference from a Tom Collins: no ice in the glass, keeping it colder and fizzier longer. Add an egg white and shake dry first for a Silver Fizz.','[{"name":"Gin","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":1,"displayAmt":null},{"name":"Simple Syrup","oz":0.5,"displayAmt":null},{"name":"Soda Water","oz":2,"displayAmt":null}]'::jsonb,null,'Fizz format')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (181,'Pink Gin','{"Classic","Martini"}','Nick','Lemon twist','#f8d8d8','Add Angostura bitters to a chilled Nick and Nora glass and swirl to coat, discarding the excess. Add chilled gin and stir briefly. No ice in the glass. Garnish with a lemon twist. A Royal Navy classic — bitters were originally prescribed for seasickness and sailors added gin to make it palatable. Plymouth gin is traditional.','[{"name":"Gin","oz":2.5,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"4 dashes"}]'::jsonb,null,'Bitters-forward riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (182,'Negroni Bianco','{"Modern Classic","Low-ABV","Bitter"}','Rocks','Grapefruit twist','#f0f0c0','Combine gin, dry vermouth, and Suze in a mixing glass with ice. Stir for 25 to 30 seconds. Strain into a rocks glass over a large ice cube. Garnish with a grapefruit twist. Substitutes Suze for Campari and dry vermouth for sweet — the result is bracingly bitter, floral, and far more delicate than a classic Negroni. Suze is traditional; Salers or other gentian bitters also work.','[{"name":"Gin","oz":1,"displayAmt":null},{"name":"Dry Vermouth","oz":1,"displayAmt":null},{"name":"Suze","oz":1,"displayAmt":null}]'::jsonb,null,'White bitter riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (183,'Cucumber Gimlet','{"Modern Classic","Martini"}','Coupe','Cucumber ribbon','#b8e8b0','Muddle 4 to 5 cucumber slices in a shaker. Add gin, lime juice, and simple syrup. Fill with ice and shake vigorously for 15 seconds. Double-strain through a fine mesh strainer into a chilled coupe. Garnish with a thin cucumber ribbon. Double-straining removes seeds and pulp. Hendricks gin is a natural pairing given its cucumber and rose notes.','[{"name":"Gin","oz":2,"displayAmt":null},{"name":"Lime Juice","oz":0.75,"displayAmt":null},{"name":"Simple Syrup","oz":0.5,"displayAmt":null},{"name":"Cucumber","oz":null,"displayAmt":"4 slices"}]'::jsonb,null,'Cucumber riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (184,'Rum Old Fashioned','{"Modern Classic","Spirit Forward"}','Rocks','Orange peel','#c07828','Add simple syrup and bitters to a rocks glass. Add dark or aged rum and stir to combine. Add a large ice cube and stir for 15 to 20 seconds until chilled. Express an orange peel over the glass and use as garnish. Aged Jamaican or Barbadian rum works beautifully — the molasses notes play a similar role to bourbons caramel.','[{"name":"Dark Rum","oz":2,"displayAmt":null},{"name":"Simple Syrup","oz":0.25,"displayAmt":null},{"name":"Angostura Bitters","oz":null,"displayAmt":"2 dashes"},{"name":"Orange Bitters","oz":null,"displayAmt":"1 dash"}]'::jsonb,null,'Rum base')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (185,'Rum Sour','{"Sour"}','Rocks','Lemon wheel, cherry','#e8a840','Dry shake rum, lemon juice, simple syrup, and egg white without ice for 10 to 12 seconds to emulsify. Add ice and shake hard for another 15 seconds. Strain into a rocks glass over ice. Garnish with a lemon wheel and cherry. Aged rum brings richness that pairs wonderfully with the egg white foam.','[{"name":"Rum","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null},{"name":"Simple Syrup","oz":0.5,"displayAmt":null},{"name":"Egg White","oz":null,"displayAmt":null}]'::jsonb,null,'Rum base')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (186,'French Martini','{"Modern Classic","Martini"}','Martini','Pineapple wedge or raspberry','#d84070','Combine vodka, Chambord or other raspberry liqueur, and pineapple juice in a shaker with ice. Shake very vigorously for 15 seconds — the pineapple juice creates a natural foam. Strain into a chilled martini glass. Garnish with a pineapple wedge or fresh raspberry. The foam on top is a signature; it comes from the pineapple juice with no egg white needed.','[{"name":"Vodka","oz":1.5,"displayAmt":null},{"name":"Raspberry Liqueur","oz":0.5,"displayAmt":null},{"name":"Pineapple Juice","oz":1.5,"displayAmt":null}]'::jsonb,null,'Chambord and pineapple riff')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (187,'Aperol Sour','{"Modern Classic","Sour","Low-ABV","Bitter"}','Rocks','Orange slice, bitters dots','#f06030','Dry shake Aperol, lemon juice, simple syrup, and egg white without ice for 10 seconds. Add ice and shake hard for 15 seconds. Strain into a rocks glass over ice. Garnish with an orange slice and a few dots of Angostura bitters on the foam. Lower ABV than most sours and beautifully bitter-sweet.','[{"name":"Aperol","oz":2,"displayAmt":null},{"name":"Lemon Juice","oz":0.75,"displayAmt":null},{"name":"Simple Syrup","oz":0.25,"displayAmt":null},{"name":"Egg White","oz":null,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (188,'Adonis','{"Classic","Low-ABV"}','Coupe','Orange twist','#b07040','Combine dry sherry, sweet vermouth, and orange bitters in a mixing glass with ice. Stir for 30 seconds. Strain into a chilled coupe. Garnish with an orange twist expressed over the glass. The Bamboos sweeter sibling — fino or amontillado sherry with sweet vermouth creates a rich low-ABV aperitivo. Named after the 1884 Broadway musical.','[{"name":"Dry Sherry","oz":2,"displayAmt":null},{"name":"Sweet Vermouth","oz":1,"displayAmt":null},{"name":"Orange Bitters","oz":null,"displayAmt":"2 dashes"}]'::jsonb,null,'Sweet vermouth version')
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;
insert into recipes (id,name,tags,glass,garnish,color,instructions,ingredients,variant_of,variant_name)
  values (189,'M&M','{"Modern Classic","Bitter"}','Rocks','Orange peel','#a06828','Combine mezcal and Amaro Montenegro in a mixing glass with ice. Stir for 20–25 seconds until well chilled. Strain into a rocks glass over a large ice cube. Express an orange peel over the glass and use as garnish. Equal parts — a bartender''s handshake. Short for Monte y Mezcal, created in 2015 by Marco Montefiori of Amaro Montenegro and popularised by Robert Krueger at Employee''s Only in New York. So beloved among bartenders it earned the nickname ''Manager''s Meeting''.','[{"name":"Mezcal","oz":1.5,"displayAmt":null},{"name":"Amaro Montenegro","oz":1.5,"displayAmt":null}]'::jsonb,null,null)
  on conflict (id) do update set name=excluded.name,tags=excluded.tags,glass=excluded.glass,garnish=excluded.garnish,color=excluded.color,instructions=excluded.instructions,ingredients=excluded.ingredients,variant_name=excluded.variant_name;

